/**
 * Minecraft 各种难度级别的枚举。
 *
 * An enumeration for the various difficulty levels of
 * Minecraft.
 */
export enum Difficulty {
    /**
     * @remarks
     * 简单难度级别。
     *
     * Easy difficulty level.
     *
     */
    Easy = 'Easy',
    /**
     * @remarks
     * 困难难度级别。
     *
     * Hard difficulty level.
     *
     */
    Hard = 'Hard',
    /**
     * @remarks
     * 普通难度级别。
     *
     * Normal difficulty level.
     *
     */
    Normal = 'Normal',
    /**
     * @remarks
     * 和平难度级别。
     *
     * Peaceful difficulty level.
     *
     */
    Peaceful = 'Peaceful',
}
